-- Hippo travel — catalog + store_content_blocks (deterministic UUIDs)
-- Apply after tenant schema + tables exist (pnpm schema:provision or Studio).
--
-- Automated (recommended): from this app directory, same .env.local as the storefront:
--   pnpm seed:apply
-- The API resolves your tenant from AURORA_API_KEY and substitutes __TENANT_UUID__ / __TENANT_SCHEMA__.
--
-- Manual: 1) Replace __TENANT_UUID__ and __TENANT_SCHEMA__ (see emit-seed-sql.mjs header example).
--         2) psql $DATABASE_URL -v ON_ERROR_STOP=1 -f init/seed.sql
--         or paste into Studio SQL editor.
--
-- Re-run safe: deletes seed SKUs/slugs for this vertical before insert.
-- After apply: reindex Meilisearch for the tenant.

BEGIN;

-- Clean previous seed rows for this vertical (idempotent)
DELETE FROM __TENANT_SCHEMA__.store_content_blocks WHERE tenant_id = '__TENANT_UUID__'::uuid AND slug LIKE 'seed-cb-travel-%';
DELETE FROM __TENANT_SCHEMA__.products WHERE tenant_id = '__TENANT_UUID__'::uuid AND sku LIKE 'SEED-HIPPO-TRAVEL-%';
DELETE FROM __TENANT_SCHEMA__.categories WHERE tenant_id = '__TENANT_UUID__'::uuid AND slug IN ('hippo-travel-luggage', 'hippo-travel-guides', 'hippo-travel-accessories');
DELETE FROM __TENANT_SCHEMA__.zones WHERE tenant_id = '__TENANT_UUID__'::uuid AND slug = 'hippo-travel-seed-zone';
DELETE FROM __TENANT_SCHEMA__.vendors WHERE tenant_id = '__TENANT_UUID__'::uuid AND id = 'ad8c39eb-0526-447d-b7f6-683d2d40512a'::uuid;

